UPDATE RECO_POLICY
   SET policy_value = #{policyValue}
 WHERE policy_id = #{policyId}

UPDATE RECO_POLICY
   SET status = #{status},
       approved_by = #{approvedBy},
       approved_at = #{approvedAt}
 WHERE policy_id = #{policyId}

UPDATE RECO_POLICY
   SET is_active = 'Y'
 WHERE policy_id = #{policyId}
